const b = $json.body || {};
const prompt = `You are a B2B sales lead qualification assistant for an automation consulting business. Analyze this inbound website lead and score it for the sales team.

Lead details:
- Name: ${b.name}
- Email: ${b.email}
- Company: ${b.company}
- Business type: ${b.biztype}
- Biggest bottleneck: ${b.bottleneck}

Return ONLY a valid JSON object with no markdown, no code fences, and no commentary. Use exactly these keys:
- lead_score: number from 1 to 10 (one decimal allowed)
- industry: one of Home Services, Agency, SaaS, Ecommerce, Real Estate, Consulting, Prof. Services, Local Service, Other
- company_size: short string such as 1-10 or 11-50
- buying_intent: one of High, Medium, Low
- priority: one of Urgent, High, Medium, Low
- opportunity_low: number in USD
- opportunity_high: number in USD
- automation_needs: array of short strings
- executive_summary: a 2 to 3 sentence summary written for the salesperson
- next_action: one sentence recommended next step

Example shape: {lead_score: 8.5, industry: Home Services, company_size: 1-10, buying_intent: High, priority: High, opportunity_low: 5000, opportunity_high: 15000, automation_needs: [dispatch automation, customer notifications], executive_summary: ..., next_action: ...}`;
return [{ json: { anthropicBody: { model: 'claude-haiku-4-5-20251001', max_tokens: 1024, messages: [{ role: 'user', content: prompt }] } } }];

const resp = $json || {};
let text = '';
if (resp.content && resp.content[0]) { text = resp.content[0].text; }
else if (resp.body && resp.body.content && resp.body.content[0]) { text = resp.body.content[0].text; }
let clean = String(text).replace(/```json/gi, '').replace(/```/g, '').trim();
let parsed = {};
try { parsed = JSON.parse(clean); } catch (e) { parsed = {}; }
const body = $('Webhook - Lead Intake').first().json.body || {};
const prioMap = { 'Urgent': '🔴 Urgent', 'High': '🟠 High', 'Medium': '🟡 Medium', 'Low': '⚪ Low' };
const priority = prioMap[parsed.priority] || '🟡 Medium';
return [{ json: {
  name: body.name || '',
  email: body.email || '',
  company: body.company || '',
  bottleneck: body.bottleneck || '',
  lead_score: parsed.lead_score != null ? parsed.lead_score : 5,
  industry: parsed.industry || 'Other',
  company_size: parsed.company_size || '',
  buying_intent: parsed.buying_intent || 'Medium',
  priority: priority,
  opportunity_low: parsed.opportunity_low != null ? parsed.opportunity_low : 0,
  opportunity_high: parsed.opportunity_high != null ? parsed.opportunity_high : 0,
  automation_needs: parsed.automation_needs || [],
  executive_summary: parsed.executive_summary || '',
  next_action: parsed.next_action || ''
}}];
